import { useState } from "react";
import { Scanner } from "@yudiel/react-qr-scanner";
import { songs } from "./songs";
import "./App.css";

function App() {
  const [song, setSong] = useState(null);

  const handleScan = (result) => {
    const id = result[0]?.rawValue;

    if (songs[id]) {
      setSong(songs[id]);
    } else {
      alert("Nie znaleziono piosenki w bazie!");
    }
  };

  return (
    <div className="App">
      <h1>Czytnik QR – Odtwarzacz piosenek</h1>

      {!song && (
        <Scanner
          onScan={handleScan}
          onError={(err) => console.error(err)}
          style={{ width: "300px" }}
        />
      )}

      {song && (
        <div>
          <h2>{song.title}</h2>
          <img
            src={song.cover}
            alt="cover"
            style={{ width: "200px", borderRadius: "10px" }}
          />

          <audio controls autoPlay style={{ marginTop: "20px" }}>
            <source src={song.file} type="audio/mp3" />
            Your browser does not support the audio element.
          </audio>

          <button onClick={() => setSong(null)} style={{ marginTop: "20px" }}>
            Skanuj następny kod
          </button>
        </div>
      )}
    </div>
  );
}

export default App;
